fixed_code:
fn main() {
    let s = String::from("hello");

    #[cfg(feature = "utf8")]
    for c in s.chars() {
        println!("{}", c);
    }

    #[cfg(not(feature = "utf8"))]
    for b in s.bytes() {
        println!("{}", char::from_u32(b as u32).unwrap());
    }
}
